import React from 'react';
import { BrowserRouter as Router, Routes, Route } from 'react-router-dom';
import FileExplorer from './components/FileExplorer'; // Asigură-te că calea este corectă
import Sidebar from './components/Sidebar';
import MicrosoftTeams from './components/MicrosoftTeams';
import MicrosoftWord from './components/MicrosoftWord';
import MicrosoftExcel from './components/MicrosoftExcel';
import PowerPoint from './components/PowerPoint';
import PDFReader from './components/PDF';
import Chrome from './components/chrome';
import Zoom from './components/Zoom';
import WhatsApp from './components/WhatsApp';
import Skype from './components/Skype';
import './App.css';

const App = () => {
  return (
    <Router>
      <div className="App">
        <Sidebar />
        <Routes>
          <Route path="/file-explorer" element={<FileExplorer />} />
          <Route path="/teams" element={<MicrosoftTeams />} />
          <Route path="/word" element={<MicrosoftWord />} />
          <Route path="/excel" element={<MicrosoftExcel />} />
          <Route path="/powerpoint" element={<PowerPoint />} />
          <Route path="/pdf-reader" element={<PDFReader />} />
          <Route path="/chrome" element={<Chrome />} />
          <Route path="/zoom" element={<Zoom />} />
          <Route path="/whatsapp" element={<WhatsApp />} />
          <Route path="/skype" element={<Skype />} />
        </Routes>
      </div>
    </Router>
  );
};

export default App;
